+    /// Compute LAG or LEAD for partition
+    fn computeLagLead(
+        self: *Self,
+        results: []i64,
+        partition: []const u32,
+        indices: []const u32,
+        args: []const Expr,
+        offset: usize,
+        default_val: i64,
+        is_lag: bool,
